INSERT INTO `notice` VALUES (1,'平台上线公告','校园外卖平台正式上线，欢迎广大师生使用，足不出户享受美食！','2026-06-11 06:10:00',0),(2,'配送时间调整','因近期天气原因，部分时段配送时间延长，请大家耐心等待。','2026-03-22 16:46:00',0),(3,'新商家入驻','本周新增多家优质商户，更多美味等你来发现。','2026-03-23 03:48:00',0),(4,'评价有奖活动','完成订单并评价，即有机会获得平台优惠券。','2026-03-27 01:26:00',0),(5,'文明用餐倡议','请大家节约粮食，按需点餐，共建文明校园。','2026-02-21 09:35:00',0),(6,'客服服务时间','平台客服服务时间为每日 8:00-22:00，如有问题请及时反馈。','2026-05-09 09:45:00',0);
/*!40000 ALTER TABLE `notice` ENABLE KEYS */;
