/*!40000 ALTER TABLE `order_item` ENABLE KEYS */;
UNLOCK TABLES;
DROP TABLE IF EXISTS `orders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `orders` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `order_no` varchar(40) COLLATE utf8mb4_general_ci NOT NULL,
  `user_id` bigint NOT NULL,
  `shop_id` bigint NOT NULL,
  `goods_amount` decimal(10,2) DEFAULT NULL,
  `pack_fee` decimal(10,2) DEFAULT NULL,
  `delivery_fee` decimal(10,2) DEFAULT NULL,
  `total_amount` decimal(10,2) DEFAULT NULL,
  `status` tinyint DEFAULT NULL COMMENT '1待支付2待接单3待配送4配送中5已完成6已取消',
  `rider_id` bigint DEFAULT NULL COMMENT '配送员ID，骑手抢单后写入',
  `address_snapshot` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `remark` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `create_time` datetime DEFAULT NULL,
  `pay_time` datetime DEFAULT NULL,
  `finish_time` datetime DEFAULT NULL,
  `accept_time` datetime DEFAULT NULL COMMENT '商家接单时间，配送时效计时起点',
  `sla_deadline` datetime DEFAULT NULL COMMENT '配送截止时间=接单时间+60分钟，延期获批后顺延',
  `extend_status` tinyint DEFAULT '0' COMMENT '延期申请：0无1待用户审批2已同意3已拒绝',
  `extend_minutes` int DEFAULT NULL COMMENT '骑手申请延长的分钟数',
  `extend_reason` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '骑手申请延期的原因',
  `deleted` tinyint DEFAULT '0',
